//! AMD fTPM EK certificate chain fixture
//! Captured from: Lucy (Anthony's laptop)
//! TPM: AMD firmware TPM, ManufacturerId 0x414D4400
//! TPM Version: 3.55.0.5
//! Captured: 2026-04-17
//!
//! Chain structure:
//!   amd_ek_cert      — device EK cert, unique to this laptop, ECC P-256
//!                      Subject: TPMVersion=id:00030001, TPMModel=AMD, TPMManufacturer=id:414D4400
//!                      Issuer: CN=PRG-RN, O=Advanced Micro Devices
//!                      Valid: 2021-04-13 → 2046-04-13
//!                      EKU: Endorsement Key Certificate (2.23.133.8.1)
//!
//!   amd_intermediate — CN=PRG-RN, AMD intermediate CA
//!                      Issuer: CN=AMDTPM, O=Advanced Micro Devices
//!                      Valid: 2019-01-01 → 2044-01-01
//!                      Thumbprint: 1997CDF507A45E79B066888F1046D5C9F131480A
//!
//!   amd_root         — CN=AMDTPM, AMD root CA, self-signed
//!                      Valid: 2016-01-01 → 2041-01-01
//!                      Thumbprint: 5C1D5CBF191314C755E29578FF734AC0095D1146
//!
//! AIA chain verification:
//!   EK cert AIA:          http://ftpm.amd.com/pki/aia/CA6EA09EB84853EC720CD9BE5AAE73BF
//!   Intermediate AIA:     http://ftpm.amd.com/pki/aia/23452201D41C5AB064032BD23F158FEF
//!   CRL:                  http://ftpm.amd.com/pki/crl
//!
//! NOTE: The EK cert is device-unique and should not be used as a
//! KNOWN_MANUFACTURER_INTERMEDIATES entry. The intermediate cert SPKI hash
//! is the correct entry for the whitelist.
//!
//! AMD_FTPM_PRG_RN_INTERMEDIATE_HASH = blake2_256(intermediate SPKI bytes)
//!   = bbe17930b14bf5000bc7656f97b032dd3ef353a2f8e9475c9814bc4136c5e323
//! Cross-verified against AMD's pki/aia path. Wired into chain.rs.

fn hex_to_bytes(hex: &str) -> Vec<u8> {
    (0..hex.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&hex[i..i + 2], 16).unwrap())
        .collect()
}

/// Device EK certificate — unique to this AMD fTPM laptop.
/// Do NOT use as a manufacturer intermediate — device-specific.
pub fn amd_ek_cert() -> Vec<u8> {
    hex_to_bytes(AMD_EK_CERT_HEX)
}

/// AMD intermediate CA — CN=PRG-RN.
/// This is the KNOWN_MANUFACTURER_INTERMEDIATES entry.
pub fn amd_intermediate_cert() -> Vec<u8> {
    hex_to_bytes(AMD_INTERMEDIATE_CERT_HEX)
}

/// AMD root CA — CN=AMDTPM, self-signed.
pub fn amd_root_cert() -> Vec<u8> {
    hex_to_bytes(AMD_ROOT_CERT_HEX)
}

/// Full chain in attestation order: [ek, intermediate, root].
pub fn amd_ftpm_chain() -> Vec<Vec<u8>> {
    vec![amd_ek_cert(), amd_intermediate_cert(), amd_root_cert()]
}

const AMD_EK_CERT_HEX: &str = "";

const AMD_INTERMEDIATE_CERT_HEX: &str = "";

const AMD_ROOT_CERT_HEX: &str = "";
